/**
 * Defense-in-depth filesystem helpers.
 *
 * Hook stdout (`{"continue":true,"suppressOutput":true}` etc.) has historically
 * leaked into path arguments via env-var or input-field misresolution and
 * ended up as a literal mkdir argument at the project root (#1250).
 *
 * Centralised guards in paths.ts/run-hook.mjs prevent the leak at read time;
 * this wrapper is the last-line defence at write time. Any path that begins
 * with `{` or `[` (i.e. looks like JSON, not a path) is rejected here.
 */

import { mkdirSync as nodeMkdirSync } from 'node:fs';
import type { MakeDirectoryOptions } from 'node:fs';

/**
 * Reject obviously-non-path strings: leading '{' or '[' (JSON), null bytes,
 * and the empty string. Returns false for anything that should not be passed
 * to mkdir / writeFile / similar.
 */
export function looksLikePath(p: unknown): p is string {
  if (typeof p !== 'string' || p.length === 0) return false;
  if (p.startsWith('{') || p.startsWith('[')) return false;
  if (p.includes('\0')) return false;
  return true;
}

/**
 * Drop-in replacement for `fs.mkdirSync` that refuses JSON-shaped paths.
 *
 * On rejection: writes a one-line warning to stderr and returns undefined
 * instead of throwing — hook handlers must never block CC because of an
 * upstream env corruption. The original mkdir would have created a literal
 * `{...}` directory; we fail closed instead.
 */
export function safeMkdirSync(
  path: string,
  options?: MakeDirectoryOptions & { recursive?: true },
): string | undefined {
  if (!looksLikePath(path)) {
    process.stderr.write(
      `[orchestkit] safeMkdirSync refused suspicious path (likely JSON leak): ${JSON.stringify(path).slice(0, 120)}\n`,
    );
    return undefined;
  }
  return nodeMkdirSync(path, options);
}
